  7	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  8	import { getErrorMessage } from '@odf/shared/utils';
  9	import { k8sPatch } from '@openshift-console/dynamic-plugin-sdk';
 10	import { TFunction } from 'react-i18next';
 11	import {
 12	  Modal,
 13	  Button,
 14	  ModalVariant,
 15	  ButtonProps,
 16	  ButtonType,
 17	  ButtonVariant,
 18	  AlertVariant,
 19	} from '@patternfly/react-core';
 20	import { DRActionType } from '../../../../constants';
 21	import {
 22	  FailoverRelocateModalBody,
 23	  findErrorMessage,
 24	} from './failover-relocate-modal-body';
 25	import {
 26	  failoverAndRelocateReducer,
 27	  failoverAndRelocateState,
 28	  ModalFooterStatus,
 29	  FailoverAndRelocateType,
 30	} from './reducer';
 31	import './failover-relocate-modal-body.scss';
 32	
 33	const generatefooterButtons = (props: ModalFooterProps): FooterButtonProps => ({
 34	  [ModalFooterStatus.INITIAL]: [
 35	    {
 36	      id: 'modal-cancel-action',
 37	      label: props.t('Cancel'),
 38	      type: ButtonType.button,
 39	      variant: ButtonVariant.link,
 40	      onClick: props.close,
 41	    },
 42	    {
 43	      id: 'modal-intiate-action',
 44	      label: props.t('Initiate'),
 45	      type: ButtonType.button,
 46	      variant: ButtonVariant.primary,
 47	      isDisabled: props?.isDisable,
 48	      onClick: props?.onClick,
 49	    },
 50	  ],
 51	  [ModalFooterStatus.INPROGRESS]: [
 52	    {
 53	      id: 'modal-cancel-action',
 54	      label: props.t('Cancel'),
 55	      type: ButtonType.button,
 56	      variant: ButtonVariant.link,
 57	      onClick: props.close,
 58	    },
 59	    {
 60	      id: 'modal-intiating-action',
 61	      label: props.t('Intiating'),
 62	      type: ButtonType.button,
 63	      variant: ButtonVariant.primary,
 64	      isLoading: true,
 65	      isDisabled: true,
 66	    },
 67	  ],
 68	  [ModalFooterStatus.FINISHED]: [
 69	    {
 70	      id: 'modal-close-action',
 71	      label: props.t('Close'),
 72	      type: ButtonType.button,
 73	      variant: ButtonVariant.secondary,
 74	      onClick: props.close,
 75	    },
 76	  ],
 77	});
 78	
 79	const getModalText = (t: TFunction) => ({
 80	  [DRActionType.FAILOVER]: {
 81	    title: t('Failover application'),
 82	    description: t(
 83	      'Failing over force stops active replication and deploys your application on the selected target cluster. Recommended only when the primary cluster is down.'
 84	    ),
 85	  },
 86	  [DRActionType.RELOCATE]: {
 87	    title: t('Relocate application'),
 88	    description: t(
 89	      'Relocating terminates your application on its current cluster, syncs its most recent snapshot to the selected target cluster, and then brings up your application.'
 90	    ),
 91	  },
 92	});
 93	
 94	export const SubscriptionFailoverRelocateModal: React.FC<
 95	  FailoverRelocateModalProps
 96	> = (props) => {
 97	  const { t } = useCustomTranslation();
 98	  const { action, isOpen, resource, close } = props;
 99	  const modalText = getModalText(t)[action];
100	
101	  const [state, dispatch] = React.useReducer(
102	    failoverAndRelocateReducer,
103	    failoverAndRelocateState(action)
104	  );
105	
106	  const updateModalStatus = (modalFooterStatus: ModalFooterStatus) =>
107	    dispatch({
108	      type: FailoverAndRelocateType.SET_MODAL_FOOTER_STATUS,
109	      payload: modalFooterStatus,
110	    });
111	
112	  const canInitiate = () =>
113	    !findErrorMessage(state.errorMessage, false) &&
114	    !!state.selectedSubsGroups.length;
115	
116	  const onClick = () => {
117	    updateModalStatus(ModalFooterStatus.INPROGRESS);
118	    const promises: Promise<K8sResourceKind>[] = [];
119	    const targetClusterName =
120	      state.selectedTargetCluster.clusterInfo.clusterName;
121	    const primaryClusterName = state.selectedDRPolicy.drClusters.find(
122	      (drCluster) => drCluster !== targetClusterName
123	    );
124	    state.drPolicyControlState.forEach((acmToDRState) => {
125	      if (
126	        state.selectedSubsGroups.includes(
127	          getName(acmToDRState?.drPlacementControl)
128	        )
129	      ) {
130	        const patch = [
131	          {
132	            op: 'replace',
133	            path: '/spec/action',
134	            value: action,
135	          },
136	          {
137	            op: 'replace',
138	            path: '/spec/failoverCluster',
139	            value:
140	              action === DRActionType.FAILOVER
141	                ? targetClusterName
142	                : primaryClusterName,
143	          },
144	          {
145	            op: 'replace',
146	            path: '/spec/preferredCluster',
147	            value:
148	              action === DRActionType.FAILOVER
149	                ? primaryClusterName
150	                : targetClusterName,
151	          },
152	        ];
153	        promises.push(
154	          k8sPatch({
155	            model: DRPlacementControlModel,
156	            resource: acmToDRState?.drPlacementControl,
157	            data: patch,
158	          })
159	        );
160	      }
161	    });
162	    Promise.all(promises)
163	      .then(() => {
164	        updateModalStatus(ModalFooterStatus.FINISHED);
165	      })
166	      .catch((error) => {
167	        updateModalStatus(ModalFooterStatus.INITIAL);
168	        dispatch({
169	          type: FailoverAndRelocateType.SET_ACTION_ERROR_MESSAGE,
170	          payload: {
171	            title: getErrorMessage(error),
172	            variant: AlertVariant.danger,
173	          },
174	        });
175	      });
176	  };
177	
178	  return (
179	    <Modal
180	      title={modalText?.title}
181	      description={modalText?.description}
182	      isOpen={isOpen}
183	      onClose={close}
184	      variant={ModalVariant.medium}
185	    >
186	      <ModalBody>
187	        <FailoverRelocateModalBody
188	          application={resource}
189	          action={action}
190	          state={state}
191	          dispatch={dispatch}
192	        />
193	      </ModalBody>
194	      <ModalFooter>
195	        {generatefooterButtons({
196	          t,
197	          close,
198	          isDisable: !canInitiate(),
199	          onClick,
200	        })[state.modalFooterStatus].map((buttonProp) => (
201	          <Button
202	            key={buttonProp.id}
203	            data-test={buttonProp.id}
204	            type={buttonProp.type}
205	            variant={buttonProp.variant}
206	            isDisabled={buttonProp.isDisabled}
207	            id={buttonProp.id}
208	            data-test-id={buttonProp.id}
209	            onClick={buttonProp.onClick}
210	            isLoading={buttonProp.isLoading}
211	          >
212	            {buttonProp.label}
213	          </Button>
214	        ))}
215	      </ModalFooter>
216	    </Modal>
217	  );
218	};
219	
220	type ModalFooterProps = {
221	  isDisable?: boolean;
222	  t: TFunction;
223	  onClick?: () => void;
224	  close?: () => void;
225	};
226	
227	type FooterButtonProps = {
228	  [status in ModalFooterStatus]?: ButtonProps[];
229	};
230	
231	type FailoverRelocateModalProps = {
232	  action: DRActionType;
233	  isOpen: boolean;
234	  resource?: ApplicationKind;
235	  close?: () => void;
236	};

