  7	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  8	import { getErrorMessage } from '@odf/shared/utils';
  9	import { k8sPatch } from '@openshift-console/dynamic-plugin-sdk';
 10	import { TFunction } from 'react-i18next';
 11	import {
 12	  Modal,
 13	  ModalHeader,
 14	  Button,
 15	  ModalVariant,
 16	  ButtonProps,
 17	  ButtonType,
 18	  ButtonVariant,
 19	  AlertVariant,
 20	} from '@patternfly/react-core';
 21	import { DRActionType } from '../../../../constants';
 22	import {
 23	  FailoverRelocateModalBody,
 24	  findErrorMessage,
 25	} from './failover-relocate-modal-body';
 26	import {
 27	  failoverAndRelocateReducer,
 28	  failoverAndRelocateState,
 29	  ModalFooterStatus,
 30	  FailoverAndRelocateType,
 31	} from './reducer';
 32	import './failover-relocate-modal-body.scss';
 33	
 34	const generatefooterButtons = (props: ModalFooterProps): FooterButtonProps => ({
 35	  [ModalFooterStatus.INITIAL]: [
 36	    {
 37	      id: 'modal-cancel-action',
 38	      label: props.t('Cancel'),
 39	      type: ButtonType.button,
 40	      variant: ButtonVariant.link,
 41	      onClick: props.close,
 42	    },
 43	    {
 44	      id: 'modal-intiate-action',
 45	      label: props.t('Initiate'),
 46	      type: ButtonType.button,
 47	      variant: ButtonVariant.primary,
 48	      isDisabled: props?.isDisable,
 49	      onClick: props?.onClick,
 50	    },
 51	  ],
 52	  [ModalFooterStatus.INPROGRESS]: [
 53	    {
 54	      id: 'modal-cancel-action',
 55	      label: props.t('Cancel'),
 56	      type: ButtonType.button,
 57	      variant: ButtonVariant.link,
 58	      onClick: props.close,
 59	    },
 60	    {
 61	      id: 'modal-intiating-action',
 62	      label: props.t('Intiating'),
 63	      type: ButtonType.button,
 64	      variant: ButtonVariant.primary,
 65	      isLoading: true,
 66	      isDisabled: true,
 67	    },
 68	  ],
 69	  [ModalFooterStatus.FINISHED]: [
 70	    {
 71	      id: 'modal-close-action',
 72	      label: props.t('Close'),
 73	      type: ButtonType.button,
 74	      variant: ButtonVariant.secondary,
 75	      onClick: props.close,
 76	    },
 77	  ],
 78	});
 79	
 80	const getModalText = (t: TFunction) => ({
 81	  [DRActionType.FAILOVER]: {
 82	    title: t('Failover application'),
 83	    description: t(
 84	      'Failing over force stops active replication and deploys your application on the selected target cluster. Recommended only when the primary cluster is down.'
 85	    ),
 86	  },
 87	  [DRActionType.RELOCATE]: {
 88	    title: t('Relocate application'),
 89	    description: t(
 90	      'Relocating terminates your application on its current cluster, syncs its most recent snapshot to the selected target cluster, and then brings up your application.'
 91	    ),
 92	  },
 93	});
 94	
 95	export const SubscriptionFailoverRelocateModal: React.FC<
 96	  FailoverRelocateModalProps
 97	> = (props) => {
 98	  const { t } = useCustomTranslation();
 99	  const { action, isOpen, resource, close } = props;
100	  const modalText = getModalText(t)[action];
101	
102	  const [state, dispatch] = React.useReducer(
103	    failoverAndRelocateReducer,
104	    failoverAndRelocateState(action)
105	  );
106	
107	  const updateModalStatus = (modalFooterStatus: ModalFooterStatus) =>
108	    dispatch({
109	      type: FailoverAndRelocateType.SET_MODAL_FOOTER_STATUS,
110	      payload: modalFooterStatus,
111	    });
112	
113	  const canInitiate = () =>
114	    !findErrorMessage(state.errorMessage, false) &&
115	    !!state.selectedSubsGroups.length;
116	
117	  const onClick = () => {
118	    updateModalStatus(ModalFooterStatus.INPROGRESS);
119	    const promises: Promise<K8sResourceKind>[] = [];
120	    const targetClusterName =
121	      state.selectedTargetCluster.clusterInfo.clusterName;
122	    const primaryClusterName = state.selectedDRPolicy.drClusters.find(
123	      (drCluster) => drCluster !== targetClusterName
124	    );
125	    state.drPolicyControlState.forEach((acmToDRState) => {
126	      if (
127	        state.selectedSubsGroups.includes(
128	          getName(acmToDRState?.drPlacementControl)
129	        )
130	      ) {
131	        const patch = [
132	          {
133	            op: 'replace',
134	            path: '/spec/action',
135	            value: action,
136	          },
137	          {
138	            op: 'replace',
139	            path: '/spec/failoverCluster',
140	            value:
141	              action === DRActionType.FAILOVER
142	                ? targetClusterName
143	                : primaryClusterName,
144	          },
145	          {
146	            op: 'replace',
147	            path: '/spec/preferredCluster',
148	            value:
149	              action === DRActionType.FAILOVER
150	                ? primaryClusterName
151	                : targetClusterName,
152	          },
153	        ];
154	        promises.push(
155	          k8sPatch({
156	            model: DRPlacementControlModel,
157	            resource: acmToDRState?.drPlacementControl,
158	            data: patch,
159	          })
160	        );
161	      }
162	    });
163	    Promise.all(promises)
164	      .then(() => {
165	        updateModalStatus(ModalFooterStatus.FINISHED);
166	      })
167	      .catch((error) => {
168	        updateModalStatus(ModalFooterStatus.INITIAL);
169	        dispatch({
170	          type: FailoverAndRelocateType.SET_ACTION_ERROR_MESSAGE,
171	          payload: {
172	            title: getErrorMessage(error),
173	            variant: AlertVariant.danger,
174	          },
175	        });
176	      });
177	  };
178	
179	  return (
180	    <Modal
181	      isOpen={isOpen}
182	      onClose={close}
183	      variant={ModalVariant.medium}
184	    >
185	      <ModalHeader title={modalText?.title} description={modalText?.description} />
186	      <ModalBody>
187	        <FailoverRelocateModalBody
188	          application={resource}
189	          action={action}
190	          state={state}
191	          dispatch={dispatch}
192	        />
193	      </ModalBody>
194	      <ModalFooter>
195	        {generatefooterButtons({
196	          t,
197	          close,
198	          isDisable: !canInitiate(),
199	          onClick,
200	        })[state.modalFooterStatus].map((buttonProp) => (
201	          <Button
202	            key={buttonProp.id}
203	            data-test={buttonProp.id}
204	            type={buttonProp.type}
205	            variant={buttonProp.variant}
206	            isDisabled={buttonProp.isDisabled}
207	            id={buttonProp.id}
208	            data-test-id={buttonProp.id}
209	            onClick={buttonProp.onClick}
210	            isLoading={buttonProp.isLoading}
211	          >
212	            {buttonProp.label}
213	          </Button>
214	        ))}
215	      </ModalFooter>
216	    </Modal>
217	  );
218	};
219	
220	type ModalFooterProps = {
221	  isDisable?: boolean;
222	  t: TFunction;
223	  onClick?: () => void;
224	  close?: () => void;
225	};
226	
227	type FooterButtonProps = {
228	  [status in ModalFooterStatus]?: ButtonProps[];
229	};
230	
231	type FailoverRelocateModalProps = {
232	  action: DRActionType;
233	  isOpen: boolean;
234	  resource?: ApplicationKind;
235	  close?: () => void;
236	};
